// lib/features/share/presentation/share_screen.dart
//
// DAXELO KINREL — Share & Invite Screen
//
// Orange K-Graph DNA design:
//   • Tab bar: "Invite" | "Share Card" | "Share Graph"
//   • Invite tab: 6 share method cards in 2-column grid
//     (Link, QR Code, WhatsApp, SMS, Email, Copy)
//     + Active invite links list
//   • Share Card tab: Beautiful kinship card with regional term,
//     English translation, relationship path, "Generated by Kinrel"
//     branding + share to WhatsApp Status / general share sheet
//   • Share Graph tab: Graph preview with export options
//     + "Created with Kinrel by Daxelo" watermark
//
// Design colors:
//   Background:  #13141E (darkSurface)
//   Cards:       #191B2C (darkCard)
//   Primary:     #F5F0EE (textWhite)
//   Secondary:   #C9B4A8 (textSilver)
//   Accent:      #E8612A (orange)
//   WhatsApp:    #25D366 (green)
//   SMS:         #3B82F6 (blue)
//   Email:       #E8612A (orange)
//   QR Code:     #F59240 (amber)
//   Copy:        #F5F0EE (white)

