// ═══════════════════════════════════════════════════════════════════════
// Tab 1: Invite — 6 share method cards + active invite links
// ═══════════════════════════════════════════════════════════════════════

class _InviteTab extends ConsumerWidget {
  const _InviteTab({required this.familyId, required this.familyName});

  final String familyId;
  final String familyName;

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    final shareState = ref.watch(
      shareProvider((familyId: familyId, familyName: familyName)),
    );
    final notifier = ref.read(
      shareProvider((familyId: familyId, familyName: familyName)).notifier,
    );
    final primaryLink = shareState.primaryLink;

    return SingleChildScrollView(
      physics: const BouncingScrollPhysics(),
      padding: const EdgeInsets.fromLTRB(
        KinrelSpacing.base,
        0,
        KinrelSpacing.base,
        40,
      ),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          // ── Invite Link Card ───────────────────────────────────────
          if (primaryLink != null)
            _InviteLinkCard(
              link: primaryLink,
              copiedToClipboard: shareState.copiedToClipboard,
              onCopy: () {
                Clipboard.setData(ClipboardData(text: primaryLink.deepLink));
                notifier.markCopied();
                ScaffoldMessenger.of(context).showSnackBar(
                  SnackBar(
                    content: Text('Link copied to clipboard!'),
                    backgroundColor: _cCard,
                    behavior: SnackBarBehavior.floating,
                    duration: const Duration(seconds: 2),
                  ),
                );
              },
            ).animate().fadeIn(duration: 350.ms).slideY(begin: 0.06, end: 0),

          const SizedBox(height: 20),

          // ── "Choose how to invite" label ───────────────────────────
          Text(
            'Choose how to invite',
            style: TextStyle(
              fontFamily: KinrelTypography.bodyFont,
              fontSize: 14,
              fontWeight: FontWeight.w600,
              color: _cTextSecondary,
            ),
          ),

          const SizedBox(height: 12),

          // ── 6 Share Method Cards (2-column grid) ──────────────────
          _ShareMethodGrid(
                primaryLink: primaryLink,
                onCopy: () {
                  if (primaryLink != null) {
                    Clipboard.setData(
                      ClipboardData(text: primaryLink.deepLink),
                    );
                    notifier.markCopied();
                    ScaffoldMessenger.of(context).showSnackBar(
                      SnackBar(
                        content: Text('Link copied to clipboard!'),
                        backgroundColor: _cCard,
                        behavior: SnackBarBehavior.floating,
                        duration: const Duration(seconds: 2),
                      ),
                    );
                  }
                },
              )
              .animate()
              .fadeIn(duration: 350.ms, delay: 100.ms)
              .slideY(begin: 0.06, end: 0),

          const SizedBox(height: 24),

          // ── Generate New Link Button ──────────────────────────────
          GestureDetector(
            onTap: () => notifier.generateLink(),
            child: Container(
              width: double.infinity,
              padding: const EdgeInsets.symmetric(vertical: 14),
              decoration: BoxDecoration(
                gradient: KinrelGradients.igniteGradient,
                borderRadius: BorderRadius.circular(KinrelRadius.lg),
                boxShadow: [
                  BoxShadow(
                    color: _cOrange.withValues(alpha: 0.3),
                    blurRadius: 12,
                    offset: const Offset(0, 4),
                  ),
                ],
              ),
              child: Row(
                mainAxisAlignment: MainAxisAlignment.center,
                children: [
                  const Icon(Icons.add_rounded, color: Colors.white, size: 20),
                  const SizedBox(width: 8),
                  Text(
                    'Generate New Link',
                    style: TextStyle(
                      fontFamily: KinrelTypography.bodyFont,
                      fontSize: 14,
                      fontWeight: FontWeight.w600,
                      color: Colors.white,
                      letterSpacing: 0.3,
                    ),
                  ),
                ],
              ),
            ),
          ),

          const SizedBox(height: 24),

          // ── Active Invite Links ───────────────────────────────────
          if (shareState.activeLinks.isNotEmpty) ...[
            Text(
              'Active Links',
              style: TextStyle(
                fontFamily: KinrelTypography.bodyFont,
                fontSize: 14,
                fontWeight: FontWeight.w600,
                color: _cTextSecondary,
              ),
            ),
            const SizedBox(height: 10),
            ...shareState.activeLinks.map(
              (link) => Padding(
                padding: const EdgeInsets.only(bottom: 10),
                child: _ActiveLinkTile(
                  link: link,
                  onDeactivate: () => notifier.deactivateLink(link.id),
                ),
              ),
            ),
          ],

          // ── Expired Links ─────────────────────────────────────────
          if (shareState.expiredLinks.isNotEmpty) ...[
            const SizedBox(height: 16),
            Text(
              'Expired Links',
              style: TextStyle(
                fontFamily: KinrelTypography.bodyFont,
                fontSize: 14,
                fontWeight: FontWeight.w600,
                color: _cTextDim,
              ),
            ),
            const SizedBox(height: 10),
            ...shareState.expiredLinks.map(
              (link) => Padding(
                padding: const EdgeInsets.only(bottom: 10),
                child: _ExpiredLinkTile(link: link),
              ),
            ),
          ],
        ],
      ),
    );
  }
}

