// ═══════════════════════════════════════════════════════════════════════
// Share Method Grid — 2-column grid of 6 invite methods
// ═══════════════════════════════════════════════════════════════════════

class _ShareMethodGrid extends StatelessWidget {
  const _ShareMethodGrid({required this.primaryLink, required this.onCopy});

  final InviteLink? primaryLink;
  final VoidCallback onCopy;

  static const _methods = [
    (
      type: InviteMethod.link,
      label: 'Link',
      icon: Icons.link_rounded,
      color: _cOrange,
    ),
    (
      type: InviteMethod.qrCode,
      label: 'QR Code',
      icon: Icons.qr_code_2_rounded,
      color: _cAmber,
    ),
    (
      type: InviteMethod.whatsapp,
      label: 'WhatsApp',
      icon: Icons.chat_rounded,
      color: _cWhatsApp,
    ),
    (
      type: InviteMethod.sms,
      label: 'SMS',
      icon: Icons.sms_rounded,
      color: _cSMS,
    ),
    (
      type: InviteMethod.email,
      label: 'Email',
      icon: Icons.email_rounded,
      color: _cEmail,
    ),
    (
      type: InviteMethod.copyLink,
      label: 'Copy Link',
      icon: Icons.copy_rounded,
      color: _cTextPrimary,
    ),
  ];

  @override
  Widget build(BuildContext context) {
    return GridView.count(
      crossAxisCount: 2,
      shrinkWrap: true,
      physics: const NeverScrollableScrollPhysics(),
      mainAxisSpacing: 10,
      crossAxisSpacing: 10,
      childAspectRatio: 2.4,
      children: _methods
          .map(
            (m) => _ShareMethodCard(
              method: m.type,
              label: m.label,
              icon: m.icon,
              color: m.color,
              primaryLink: primaryLink,
              onCopy: onCopy,
            ),
          )
          .toList(),
    );
  }
}

// ═══════════════════════════════════════════════════════════════════════
// Share Method Card — Individual invite method tile
// ═══════════════════════════════════════════════════════════════════════

class _ShareMethodCard extends StatelessWidget {
  const _ShareMethodCard({
    required this.method,
    required this.label,
    required this.icon,
    required this.color,
    required this.primaryLink,
    required this.onCopy,
  });

  final InviteMethod method;
  final String label;
  final IconData icon;
  final Color color;
  final InviteLink? primaryLink;
  final VoidCallback onCopy;

  @override
  Widget build(BuildContext context) {
    return GestureDetector(
      onTap: () => _handleTap(context),
      child: Container(
        padding: const EdgeInsets.symmetric(horizontal: 14, vertical: 12),
        decoration: BoxDecoration(
          color: _cCard,
          borderRadius: BorderRadius.circular(KinrelRadius.lg),
          border: Border.all(color: color.withValues(alpha: 0.12), width: 1),
        ),
        child: Row(
          children: [
            Container(
              padding: const EdgeInsets.all(8),
              decoration: BoxDecoration(
                color: color.withValues(alpha: 0.12),
                borderRadius: BorderRadius.circular(KinrelRadius.md),
              ),
              child: Icon(icon, size: 20, color: color),
            ),
            const SizedBox(width: 10),
            Expanded(
              child: Text(
                label,
                style: TextStyle(
                  fontFamily: KinrelTypography.bodyFont,
                  fontSize: 13,
                  fontWeight: FontWeight.w600,
                  color: _cTextPrimary,
                ),
              ),
            ),
            Icon(Icons.chevron_right_rounded, size: 18, color: _cTextDim),
          ],
        ),
      ),
    );
  }

  void _handleTap(BuildContext context) {
    switch (method) {
      case InviteMethod.link:
        _showLinkDialog(context);
      case InviteMethod.qrCode:
        _showQRCodeSheet(context);
      case InviteMethod.whatsapp:
        _showWhatsAppSheet(context);
      case InviteMethod.sms:
        _showSMSSheet(context);
      case InviteMethod.email:
        _showEmailSheet(context);
      case InviteMethod.copyLink:
        onCopy();
    }
  }

  void _showLinkDialog(BuildContext context) {
    showModalBottomSheet(
      context: context,
      backgroundColor: _cCard,
      shape: const RoundedRectangleBorder(
        borderRadius: BorderRadius.vertical(
          top: Radius.circular(KinrelRadius.bottomSheet),
        ),
      ),
      builder: (ctx) => _LinkDetailSheet(link: primaryLink, onCopy: onCopy),
    );
  }

  void _showQRCodeSheet(BuildContext context) {
    showModalBottomSheet(
      context: context,
      backgroundColor: _cCard,
      shape: const RoundedRectangleBorder(
        borderRadius: BorderRadius.vertical(
          top: Radius.circular(KinrelRadius.bottomSheet),
        ),
      ),
      builder: (ctx) => _QRCodeSheet(link: primaryLink),
    );
  }

  void _showWhatsAppSheet(BuildContext context) {
    showModalBottomSheet(
      context: context,
      backgroundColor: _cCard,
      shape: const RoundedRectangleBorder(
        borderRadius: BorderRadius.vertical(
          top: Radius.circular(KinrelRadius.bottomSheet),
        ),
      ),
      builder: (ctx) => _WhatsAppSheet(link: primaryLink),
    );
  }

  void _showSMSSheet(BuildContext context) {
    showModalBottomSheet(
      context: context,
      backgroundColor: _cCard,
