// ── Simple Tree Line Painter ─────────────────────────────────────────

class _SimpleTreeLinePainter extends CustomPainter {
  @override
  void paint(Canvas canvas, Size size) {
    final paint = Paint()
      ..color = _cOrange.withValues(alpha: 0.15)
      ..strokeWidth = 1
      ..style = PaintingStyle.stroke;

    final width = size.width;
    final midY = size.height / 2;

    // Horizontal line
    canvas.drawLine(
      Offset(width * 0.15, midY),
      Offset(width * 0.85, midY),
      paint,
    );

    // Vertical connectors
    final positions = [0.25, 0.45, 0.65, 0.8];
    for (final x in positions) {
      canvas.drawLine(
        Offset(width * x, midY - 6),
        Offset(width * x, midY + 6),
        paint,
      );
    }
  }

  @override
  bool shouldRepaint(covariant CustomPainter oldDelegate) => false;
}

