        const SizedBox(height: 8),

        // PDF export
        _ExportOptionTile(
          icon: Icons.picture_as_pdf_rounded,
          title: 'PDF Document',
          subtitle: 'Vector quality · A4 layout',
          color: _cSMS,
          onTap: () {
            ScaffoldMessenger.of(context).showSnackBar(
              SnackBar(
